from hermes_tools import terminal
import json

# 查看 channel_directory.json 完整内容
result = terminal("cat ~/.hermes/channel_directory.json")
data = json.loads(result['output'])

print("=== 已配对的通讯工具 ===")
for platform, channels in data['platforms'].items():
    if channels:
        print(f"\n✅ {platform.upper()}")
        for ch in channels:
            print(f"   - ID: {ch['id']}")
            print(f"   - 类型: {ch['type']}")
            if ch.get('thread_id'):
                print(f"   - Thread: {ch['thread_id']}")
    else:
        print(f"❌ {platform}")
"}

